import React from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import ProductCard from './components/ProductCard';

function App() {
  return (
    <div className="min-h-screen bg-gray-100 flex flex-col">
      <Header />

      <main className="main-content">
        <h2 className="section-title fade-in">Nuestras Zapatillas</h2>
        <p className="section-description fade-in">Explora nuestra amplia gama...</p>

        <div className="filter-bar fade-in" style={{ animationDelay: '0.2s' }}>
          {/* botones de filtro */}
        </div>

        <div className="card-grid">
          <ProductCard title="Air Force Runner" category="Running" price="89.99" originalPrice="120.00" discount="25" tag="NUEVO" />
          <ProductCard title="Urban Street Pro" category="Casual" price="75.99" />
          <ProductCard title="Elite Jumper X" category="Basketball" price="129.99" originalPrice="150.00" discount="13" tag="HOT" />
        </div>

        {/* Banner promocional puede ir en otro componente también */}
      </main>

      <Footer />
    </div>
  );
}

export default App;
